private void populateCache(PersistentEntities entities, RepositoryRestConfiguration configuration) {

	for (PersistentEntity<?, ? extends PersistentProperty<?>> entity : entities) {

		Class<?> type = entity.getType();

		if (!repositories.hasRepositoryFor(type)) {
			continue;
		}

		RepositoryInformation repositoryInformation = repositories.getRequiredRepositoryInformation(type);
		Class<?> repositoryInterface = repositoryInformation.getRepositoryInterface();

		RepositoryDetectionStrategy strategy = configuration.getRepositoryDetectionStrategy();
		LinkRelationProvider provider = configuration.getLinkRelationProvider();

		CollectionResourceMapping mapping = new RepositoryCollectionResourceMapping(repositoryInformation, strategy,
				provider);
		RepositoryAwareResourceMetadata information = new RepositoryAwareResourceMetadata(entity, mapping, this,
				repositoryInformation);

		addToCache(repositoryInterface, information);

		if (!hasMetadataFor(type) || information.isPrimary()) {
			addToCache(type, information);
		}
	}
}

@Override
		protected <T> T handleRetryExhausted(RecoveryCallback<T> recoveryCallback, RetryContext context,
				RetryState state) throws Throwable {

			BatchRetryState batchState = (BatchRetryState) state;
			BatchRetryContext batchContext = (BatchRetryContext) context;

			// Accumulate exceptions to be thrown so all the keys get a crack
			Throwable rethrowable = null;
			ExhaustedRetryException exhausted = null;

			Iterator<RetryContext> contextIterator = batchContext.contexts.iterator();
			for (RetryState retryState : batchState.keys) {

				RetryContext nextContext = contextIterator.next();

				try {
					super.handleRetryExhausted(null, nextContext, retryState);
				}
				catch (ExhaustedRetryException e) {
					exhausted = e;
				}
				catch (Throwable e) {
					rethrowable = e;
				}

			}

			if (recoveryCallback != null) {
				return recoveryCallback.recover(context);
			}

			if (exhausted != null) {
				throw exhausted;
			}

			throw rethrowable;

		}

private void postProcessManagedTypes(ConfigurableListableBeanFactory beanFactory, BeanDefinitionRegistry registry,
			String beanName) {

		BeanDefinition beanDefinition = beanFactory.getBeanDefinition(beanName);

		if (hasConstructorArguments(beanDefinition)) {

			ValueHolder holder = beanDefinition.getConstructorArgumentValues().getArgumentValue(0, null, null, null);

			if (holder != null && holder.getValue() instanceof Supplier<?> supplier) {

				if (logger.isDebugEnabled()) {
					logger.info(String.format("Replacing ManagedType bean definition %s.", beanName));
				}

				Object value = potentiallyWrapToIterable(supplier.get());
				String beanClassName = beanDefinition.getBeanClassName();

				if (beanClassName != null) {

					BeanDefinition beanDefinitionReplacement = newManagedTypeBeanDefinition(beanClassName, value);

					registry.removeBeanDefinition(beanName);
					registry.registerBeanDefinition(beanName, beanDefinitionReplacement);
				}
			}
		}
	}

private void potentiallyRegisterRepositoryFragment(RepositoryConfiguration<?> configuration,
			RepositoryFragmentConfiguration fragmentConfiguration) {

		String beanName = fragmentConfiguration.getFragmentBeanName();

		// Already a bean configured?
		if (registry.containsBeanDefinition(beanName)) {

			if (logger.isDebugEnabled()) {
				logger.debug(String.format("RepositoryFragment already registered: %s", beanName));
			}

			return;
		}

		if (logger.isDebugEnabled()) {
			logger.debug(String.format("Registering RepositoryFragment: %s", beanName));
		}

		BeanDefinitionBuilder fragmentBuilder = BeanDefinitionBuilder.rootBeanDefinition(RepositoryFragment.class,
				"implemented");

		if (StringUtils.hasText(fragmentConfiguration.getInterfaceName())) {
			fragmentBuilder.addConstructorArgValue(fragmentConfiguration.getInterfaceName());
		}
		fragmentBuilder.addConstructorArgReference(fragmentConfiguration.getImplementationBeanName());

		registry.registerBeanDefinition(beanName,
				ParsingUtils.getSourceBeanDefinition(fragmentBuilder, configuration.getSource()));
	}

@Override
	@Nullable
	public BeanDefinition parse(Element element, ParserContext parser) {

		XmlReaderContext readerContext = parser.getReaderContext();

		try {

			ResourceLoader resourceLoader = ConfigurationUtils.getRequiredResourceLoader(readerContext);
			Environment environment = readerContext.getEnvironment();
			BeanDefinitionRegistry registry = parser.getRegistry();

			XmlRepositoryConfigurationSource configSource = new XmlRepositoryConfigurationSource(element, parser,
					environment);
			RepositoryConfigurationDelegate delegate = new RepositoryConfigurationDelegate(configSource, resourceLoader,
					environment);

			RepositoryConfigurationUtils.exposeRegistration(extension, registry, configSource);

			for (BeanComponentDefinition definition : delegate.registerRepositoriesIn(registry, extension)) {
				readerContext.fireComponentRegistered(definition);
			}

		} catch (RuntimeException e) {
			handleError(e, element, readerContext);
		}

		return null;
	}

private @Nullable String lookupSharedEntityManagerBeanRef(String entityManagerBeanRef,
			BeanDefinitionRegistry registry) {

		if (!registry.containsBeanDefinition(entityManagerBeanRef)) {
			return null;
		}

		BeanDefinitionRegistry introspect = registry;

		if (introspect instanceof ConfigurableApplicationContext cac
				&& cac.getBeanFactory() instanceof BeanDefinitionRegistry br) {
			introspect = br;
		}

		if (!(introspect instanceof ConfigurableBeanFactory cbf)) {
			return null;
		}

		BeanDefinition beanDefinition = cbf.getMergedBeanDefinition(entityManagerBeanRef);

		if (ObjectUtils.isEmpty(beanDefinition.getBeanClassName())) {
			return null;
		}

		Class<?> beanClass = org.springframework.data.util.ClassUtils.loadIfPresent(beanDefinition.getBeanClassName(),
				getClass().getClassLoader());

		// AbstractEntityManagerFactoryBean is able to create a SharedEntityManager
		return beanClass != null && AbstractEntityManagerFactoryBean.class.isAssignableFrom(beanClass)
				? entityManagerBeanRef
				: null;
	}

public static SelectStep selectFrom(Entity from) {

	return new SelectStep() {

		boolean distinct = false;

		@Override
		public SelectStep distinct() {

			distinct = true;
			return this;
		}

		@Override
		public Select entity() {
			return new Select(postProcess(new EntitySelection(from)), from);
		}

		@Override
		public Select count() {
			return new Select(new CountSelection(from, distinct), from);
		}

		@Override
		public Select instantiate(String resultType, Collection<? extends JpqlQueryBuilder.Expression> paths) {
			return new Select(postProcess(new ConstructorExpression(resultType, new Multiselect(from, paths))), from);
		}

		@Override
		public Select select(Collection<? extends JpqlQueryBuilder.Expression> paths) {
			return new Select(postProcess(new Multiselect(from, paths)), from);
		}

		@Override
		public Select select(Selection selection) {
			return new Select(postProcess(selection), from);
		}

		Selection postProcess(Selection selection) {
			return distinct ? new DistinctSelection(selection) : selection;
		}

	};
}

@Override
	public final void doFilter(ServletRequest request, ServletResponse response, FilterChain filterChain)
			throws ServletException, IOException {

		if (!(request instanceof HttpServletRequest) || !(response instanceof HttpServletResponse)) {
			throw new ServletException("OncePerRequestFilter just supports HTTP requests");
		}
		HttpServletRequest httpRequest = (HttpServletRequest) request;
		HttpServletResponse httpResponse = (HttpServletResponse) response;
		String alreadyFilteredAttributeName = getAlreadyFilteredAttributeName();
		boolean hasAlreadyFilteredAttribute = request.getAttribute(alreadyFilteredAttributeName) != null;

		if (hasAlreadyFilteredAttribute) {
			if (DispatcherType.ERROR.equals(request.getDispatcherType())) {
				doFilterNestedErrorDispatch(httpRequest, httpResponse, filterChain);
				return;
			}
			// Proceed without invoking this filter...
			filterChain.doFilter(request, response);
		}
		else {
			// Do invoke this filter...
			request.setAttribute(alreadyFilteredAttributeName, Boolean.TRUE);
			try {
				doFilterInternal(httpRequest, httpResponse, filterChain);
			}
			finally {
				// Remove the "already filtered" request attribute for this request.
				request.removeAttribute(alreadyFilteredAttributeName);
			}
		}
	}

@Override
	public GlobalKTable createInput(String name) {
		BindingProperties bindingProperties = this.bindingServiceProperties.getBindingProperties(name);
		ConsumerProperties consumerProperties = bindingProperties.getConsumer();
		if (consumerProperties == null) {
			consumerProperties = this.bindingServiceProperties.getConsumerProperties(name);
			consumerProperties.setUseNativeDecoding(true);
		}
		else {
			if (!encodingDecodingBindAdviceHandler.isDecodingSettingProvided()) {
				consumerProperties.setUseNativeDecoding(true);
			}
		}
		// Always set multiplex to true in the kafka streams binder
		consumerProperties.setMultiplex(true);

		// @checkstyle:off
		GlobalKTableBoundElementFactory.GlobalKTableWrapperHandler wrapper = new GlobalKTableBoundElementFactory.GlobalKTableWrapperHandler();
		// @checkstyle:on
		ProxyFactory proxyFactory = new ProxyFactory(
				GlobalKTableBoundElementFactory.GlobalKTableWrapper.class,
				GlobalKTable.class);
		proxyFactory.addAdvice(wrapper);

		final GlobalKTable proxy = (GlobalKTable) proxyFactory.getProxy();
		this.kafkaStreamsBindingInformationCatalogue.addBindingNamePerTarget(proxy, name);
		return proxy;
	}

@Override
	public void onMessage(Message message, @Nullable Channel channel) throws Exception {
		// Check whether the delegate is a MessageListener impl itself.
		// In that case, the adapter will simply act as a pass-through.
		Object delegateListener = getDelegate();
		if (!delegateListener.equals(this)) {
			if (delegateListener instanceof ChannelAwareMessageListener chaml) {
				chaml.onMessage(message, channel);
				return;
			}
			else if (delegateListener instanceof MessageListener messageListener) {
				messageListener.onMessage(message);
				return;
			}
		}

		// Regular case: find a handler method reflectively.
		Object convertedMessage = extractMessage(message);
		String methodName = getListenerMethodName(message, convertedMessage);

		// Invoke the handler method with appropriate arguments.
		Object[] listenerArguments = buildListenerArguments(convertedMessage, channel, message);
		Object result = invokeListenerMethod(methodName, listenerArguments, message);
		if (result != null) {
			handleResult(new InvocationResult(result, null, null, null, null), message, channel);
		}
		else {
			logger.trace("No result object given - no result to handle");
		}
	}

@Override
	public void onInit() {
		super.onInit();
		this.dispatcher = createDispatcher();
		Integer maxSubscribersToCheck = this.maxSubscribers;
		if (maxSubscribersToCheck == null) {
			int newMaxSubscribers =
					this.isPubSub
							? getIntegrationProperties().getChannelsMaxBroadcastSubscribers()
							: getIntegrationProperties().getChannelsMaxUnicastSubscribers();
			setMaxSubscribers(newMaxSubscribers);
		}
		else {
			this.dispatcher.setMaxSubscribers(maxSubscribersToCheck);
		}
		String queue = obtainQueueName(this.channelName);
		this.container.setQueueNames(queue);
		MessageConverter converter =
				(getAmqpTemplate() instanceof RabbitTemplate rabbitTemplate)
						? rabbitTemplate.getMessageConverter()
						: new SimpleMessageConverter();

		MessageListener listener =
				new DispatchingMessageListener(converter, this.dispatcher, this, this.isPubSub,
						getMessageBuilderFactory(), getInboundHeaderMapper());
		this.container.setMessageListener(listener);
		if (!this.container.isActive()) {
			this.container.afterPropertiesSet();
		}
	}

@Override
	protected BeanDefinition resolveHandlerBeanDefinition(String beanName, AnnotatedBeanDefinition beanDefinition,
			ResolvableType handlerBeanType, List<Annotation> annotations) {

		BeanDefinition handlerBeanDefinition =
				super.resolveHandlerBeanDefinition(beanName, beanDefinition, handlerBeanType, annotations);

		if (handlerBeanDefinition != null) {
			return handlerBeanDefinition;
		}

		BeanMetadataElement targetObjectBeanDefinition = buildLambdaMessageProcessor(handlerBeanType, beanDefinition);
		if (targetObjectBeanDefinition == null) {
			targetObjectBeanDefinition = new RuntimeBeanReference(beanName);
		}

		BeanDefinition filterBeanDefinition =
				BeanDefinitionBuilder.genericBeanDefinition(FilterFactoryBean.class)
						.addPropertyValue("targetObject", targetObjectBeanDefinition)
						.getBeanDefinition();

		new BeanDefinitionPropertiesMapper(filterBeanDefinition, annotations)
				.setPropertyValue("discardWithinAdvice")
				.setPropertyValue("throwExceptionOnRejection")
				.setPropertyReference("discardChannel");

		return filterBeanDefinition;
	}

@Override
	protected MessageHandler createHandler(Object bean, Method method, List<Annotation> annotations) {
		Assert.isTrue(boolean.class.equals(method.getReturnType()) || Boolean.class.equals(method.getReturnType()),
				"The Filter annotation may only be applied to methods with a boolean return type.");
		MessageSelector selector = new MethodInvokingSelector(bean, method);

		MessageFilter filter = new MessageFilter(selector);

		String discardWithinAdvice =
				MessagingAnnotationUtils.resolveAttribute(annotations, "discardWithinAdvice", String.class);
		if (StringUtils.hasText(discardWithinAdvice)) {
			filter.setDiscardWithinAdvice(resolveAttributeToBoolean(discardWithinAdvice));
		}

		String throwExceptionOnRejection =
				MessagingAnnotationUtils.resolveAttribute(annotations, "throwExceptionOnRejection", String.class);
		if (StringUtils.hasText(throwExceptionOnRejection)) {
			filter.setThrowExceptionOnRejection(resolveAttributeToBoolean(throwExceptionOnRejection));
		}

		String discardChannelName =
				MessagingAnnotationUtils.resolveAttribute(annotations, "discardChannel", String.class);
		if (StringUtils.hasText(discardChannelName)) {
			filter.setDiscardChannelName(discardChannelName);
		}

		setOutputChannelIfPresent(annotations, filter);
		return filter;
	}

private BeanMetadataElement parseExpression(String expressionString, @Nullable Element expressionElement, Element element,
			ParserContext parserContext) {

		BeanDefinitionBuilder sourceBuilder = BeanDefinitionBuilder
				.genericBeanDefinition(ExpressionEvaluatingMessageSource.class);

		BeanDefinition expressionDef;

		if (StringUtils.hasText(expressionString)) {
			expressionDef = new RootBeanDefinition(ExpressionFactoryBean.class);
			expressionDef.getConstructorArgumentValues().addGenericArgumentValue(expressionString);
		}
		else {
			BeanDefinitionBuilder dynamicExpressionBuilder = BeanDefinitionBuilder.genericBeanDefinition(
					DynamicExpression.class);
			String key = Objects.requireNonNull(expressionElement).getAttribute("key");
			String expressionSourceReference = expressionElement.getAttribute("source");
			dynamicExpressionBuilder.addConstructorArgValue(key);
			dynamicExpressionBuilder.addConstructorArgReference(expressionSourceReference);
			expressionDef = dynamicExpressionBuilder.getBeanDefinition();
		}

		sourceBuilder.addConstructorArgValue(expressionDef);
		sourceBuilder.addConstructorArgValue(null);

		this.parseHeaderExpressions(sourceBuilder, element, parserContext);
		return sourceBuilder.getBeanDefinition();
	}

@Nullable
	private IntegrationResourceHolder bindResourceHolderIfNecessary(@Nullable String key, @Nullable Object resource) {
		if (this.transactionSynchronizationFactory != null && resource != null &&
				TransactionSynchronizationManager.isActualTransactionActive()) {

			TransactionSynchronization synchronization = this.transactionSynchronizationFactory.create(resource);
			if (synchronization != null) {
				TransactionSynchronizationManager.registerSynchronization(synchronization);

				if (synchronization instanceof IntegrationResourceHolderSynchronization integrationSynchronization) {
					integrationSynchronization.setShouldUnbindAtCompletion(false);

					if (!TransactionSynchronizationManager.hasResource(resource)) {
						TransactionSynchronizationManager.bindResource(resource,
								integrationSynchronization.getResourceHolder());
					}
				}
			}

			Object resourceHolder = TransactionSynchronizationManager.getResource(resource);
			if (resourceHolder instanceof IntegrationResourceHolder integrationResourceHolder) {
				if (key != null) {
					integrationResourceHolder.addAttribute(key, resource);
				}
				return integrationResourceHolder;
			}
		}

		return null;
	}

protected void sendOutput(Object output, @Nullable Object replyChannelArg, boolean useArgChannel) {
	Object replyChannel = replyChannelArg;
	MessageChannel outChannel = getOutputChannel();
	if (!useArgChannel && outChannel != null) {
		replyChannel = outChannel;
	}
	if (replyChannel == null) {
		throw new DestinationResolutionException("no output-channel or replyChannel header available");
	}

	if (replyChannel instanceof MessageChannel messageChannel) {
		if (output instanceof Message<?> message) {
			this.messagingTemplate.send(messageChannel, message);
		}
		else {
			this.messagingTemplate.convertAndSend(messageChannel, output);
		}
	}
	else if (replyChannel instanceof String string) {
		if (output instanceof Message<?> message) {
			this.messagingTemplate.send(string, message);
		}
		else {
			this.messagingTemplate.convertAndSend(string, output);
		}
	}
	else {
		throw new MessagingException("replyChannel must be a MessageChannel or String");
	}
}

private List<HandlerMethodArgumentResolver> buildArgumentResolvers(boolean listCapable) {
	List<HandlerMethodArgumentResolver> resolvers = new ArrayList<>(6);
	resolvers.add(new PayloadExpressionArgumentResolver());
	resolvers.add(new NullAwarePayloadArgumentResolver(this.messageConverter));
	resolvers.add(new PayloadsArgumentResolver());
	if (listCapable) {
		resolvers.add(new CollectionArgumentResolver(true));
	}
	resolvers.add(new MapArgumentResolver());
	if (KotlinDetector.isKotlinPresent()) {
		resolvers.add(new ContinuationHandlerMethodArgumentResolver());
	}

	for (HandlerMethodArgumentResolver resolver : resolvers) {
		if (resolver instanceof BeanFactoryAware beanFactoryAware) {
			beanFactoryAware.setBeanFactory(this.beanFactory);
		}
		if (resolver instanceof InitializingBean initializingBean) {
			try {
				initializingBean.afterPropertiesSet();
			}
			catch (Exception ex) {
				throw new BeanInitializationException("Cannot initialize 'HandlerMethodArgumentResolver'", ex);
			}
		}
	}
	return resolvers;
}

@Override
		public boolean send(Message<?> message, long timeout) {
			this.replyMessage = message;
			boolean alreadyReceivedReply = this.hasReceived;
			this.replyLatch.countDown();

			String errorDescription = null;
			if (this.hasTimedOut) {
				errorDescription = "Reply message received but the receiving thread has exited due to a timeout";
			}
			else if (alreadyReceivedReply) {
				errorDescription = "Reply message received but the receiving thread has already received a reply";
			}
			else if (this.hasSendFailed) {
				errorDescription = "Reply message received but the receiving thread has exited due to " +
						"an exception while sending the request message";
			}

			if (errorDescription != null) {
				if (logger.isWarnEnabled()) {
					logger.warn(errorDescription + ": " + message);
				}
				if (this.throwExceptionOnLateReply) {
					throw new MessageDeliveryException(message, errorDescription);
				}
			}

			return true;
		}

@Override
	public void afterPropertiesSet() throws Exception {

		Assert.state(dataSource != null, "DataSource must not be null.");

		if (jdbcOperations == null) {
			jdbcOperations = new JdbcTemplate(dataSource);
		}

		if (jobKeyGenerator == null) {
			jobKeyGenerator = new DefaultJobKeyGenerator();
		}

		if (serializer == null) {
			serializer = new DefaultExecutionContextSerializer();
		}

		if (this.conversionService == null) {
			DefaultConversionService conversionService = new DefaultConversionService();
			conversionService.addConverter(new DateToStringConverter());
			conversionService.addConverter(new StringToDateConverter());
			conversionService.addConverter(new LocalDateToStringConverter());
			conversionService.addConverter(new StringToLocalDateConverter());
			conversionService.addConverter(new LocalTimeToStringConverter());
			conversionService.addConverter(new StringToLocalTimeConverter());
			conversionService.addConverter(new LocalDateTimeToStringConverter());
			conversionService.addConverter(new StringToLocalDateTimeConverter());
			this.conversionService = conversionService;
		}

		super.afterPropertiesSet();
	}

public static RuntimeException convertRabbitAccessException(@Nullable Throwable ex) {
	if (ex instanceof AmqpException amqpException) {
		return amqpException;
	}
	if (ex instanceof ShutdownSignalException sigEx) {
		return new AmqpConnectException(sigEx);
	}
	if (ex instanceof ConnectException connEx) {
		return new AmqpConnectException(connEx);
	}
	if (ex instanceof PossibleAuthenticationFailureException) {
		return new AmqpAuthenticationException(ex);
	}
	if (ex instanceof UnsupportedEncodingException) {
		return new AmqpUnsupportedEncodingException(ex);
	}
	if (ex instanceof IOException ioEx) {
		return new AmqpIOException(ioEx);
	}
	if (ex instanceof TimeoutException) {
		return new AmqpTimeoutException(ex);
	}
	if (ex instanceof ConsumerCancelledException) {
		return new org.springframework.amqp.rabbit.support.ConsumerCancelledException(ex);
	}
	if (ex instanceof org.springframework.amqp.rabbit.support.ConsumerCancelledException consumerCancelledException) {
		return consumerCancelledException;
	}
	// fallback
	return new UncategorizedAmqpException(ex);
}
